// Gate G0 — Valida assinatura HMAC, tamanho, mime_type e ingestion_id UUID
// Falha: responde com status_code correspondente e encerra o fluxo

const crypto = require('crypto');

const payload = $input.first();
const body = payload.json.body || payload.json;
const headers = payload.json.headers || {};

// Recupera signature do header (case-insensitive)
const receivedSignature = headers['x-gca-signature'] || headers['X-GCA-Signature'] || '';
const webhookSecret = $env.GCA_WEBHOOK_SECRET || '';

// --- Validação HMAC ---
const rawBody = JSON.stringify(body);
const expectedSignature = 'sha256=' + crypto
  .createHmac('sha256', webhookSecret)
  .update(rawBody)
  .digest('hex');

if (!webhookSecret) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'GCA_WEBHOOK_SECRET não configurado no ambiente n8n',
      _http_status: 500,
      ingestion_id: body.ingestion_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

if (!receivedSignature) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'Header X-GCA-Signature ausente',
      _http_status: 401,
      ingestion_id: body.ingestion_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

const sigValid = crypto.timingSafeEqual(
  Buffer.from(receivedSignature),
  Buffer.from(expectedSignature)
);

if (!sigValid) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'Assinatura HMAC inválida',
      _http_status: 401,
      ingestion_id: body.ingestion_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação tamanho ≤ 50MB ---
const sizeBytes = body.document_metadata?.size_bytes || 0;
const MAX_SIZE = parseInt($env.MAX_DOC_SIZE_BYTES || '52428800', 10);

if (sizeBytes > MAX_SIZE) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: `Documento excede limite de ${MAX_SIZE} bytes. Recebido: ${sizeBytes} bytes`,
      _http_status: 413,
      ingestion_id: body.ingestion_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação mime_type permitido ---
const ALLOWED_MIMES = [
  'text/plain',
  'text/markdown',
  'text/html',
  'application/json',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/pdf',
  'image/png',
  'image/jpeg',
  'image/webp',
  'message/rfc822'
];

const mimeType = body.document_metadata?.mime_type || '';

if (!mimeType || !ALLOWED_MIMES.includes(mimeType)) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: `mime_type não suportado: '${mimeType}'. Permitidos: ${ALLOWED_MIMES.join(', ')}`,
      _http_status: 415,
      ingestion_id: body.ingestion_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação ingestion_id UUID v4 ---
const UUID_V4_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const ingestionId = body.ingestion_id || '';

if (!UUID_V4_REGEX.test(ingestionId)) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: `ingestion_id inválido ou não é UUID v4: '${ingestionId}'`,
      _http_status: 422,
      ingestion_id: ingestionId || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação campos obrigatórios ---
if (!body.document_bytes_base64) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'Campo document_bytes_base64 ausente ou vazio',
      _http_status: 422,
      ingestion_id: ingestionId,
      callback_url: body.callback_url || null
    }
  }];
}

if (!body.project_id) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'Campo project_id ausente',
      _http_status: 422,
      ingestion_id: ingestionId,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação provider_chain ---
const providerChain = body.provider_chain || [];
if (!Array.isArray(providerChain) || providerChain.length === 0) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'provider_chain ausente ou vazio. Configure em Settings > IA no GCA',
      _http_status: 422,
      ingestion_id: ingestionId,
      callback_url: body.callback_url || null
    }
  }];
}

// G0 aprovado — propaga payload completo com marcação de status
return [{
  json: {
    _g0_status: 'ok',
    ingestion_id: ingestionId,
    project_id: body.project_id,
    document_bytes_base64: body.document_bytes_base64,
    document_metadata: body.document_metadata,
    provider_chain: body.provider_chain,
    callback_url: body.callback_url,
    timestamp: body.timestamp,
    _received_at: new Date().toISOString()
  }
}];

// Detecta o formato do documento e define estratégia de extração
// Conforme spec §4.2 — suporta: txt, md, html, json, docx, pdf, pdf_scanned, image/*, email

const item = $input.first().json;
const mimeType = item.document_metadata?.mime_type || '';
const filename = item.document_metadata?.filename || '';
const extension = filename.split('.').pop()?.toLowerCase() || '';

// Decodifica bytes para inspeção de magic bytes
let rawBuffer = null;
try {
  rawBuffer = Buffer.from(item.document_bytes_base64, 'base64');
} catch (e) {
  return [{
    json: {
      ...item,
      _detection_status: 'failed',
      _detection_error: `Falha ao decodificar base64: ${e.message}`,
      _g1_reason: 'g1_normalization_failed',
      _g1_detail: 'document_bytes_base64 inválido — não é base64 válido'
    }
  }];
}

// Magic bytes para detecção adicional
const magicPDF = rawBuffer.slice(0, 4).toString('ascii') === '%PDF';
const magicDOCX = rawBuffer.slice(0, 4).toString('hex') === '504b0304'; // PK zip (DOCX/XLSX/etc.)
const magicPNG = rawBuffer.slice(0, 4).toString('hex') === '89504e47';
const magicJPEG = rawBuffer.slice(0, 2).toString('hex') === 'ffd8';

let strategy = 'unknown';
let extractionMethod = 'unknown';
let needsOCR = false;
let sourceFormat = 'unknown';

// Estratégia por mime_type (com fallback para magic bytes)
if (mimeType === 'text/plain' || extension === 'txt') {
  strategy = 'passthrough';
  extractionMethod = 'passthrough';
  sourceFormat = 'txt';
  needsOCR = false;

} else if (mimeType === 'text/markdown' || extension === 'md') {
  strategy = 'passthrough';
  extractionMethod = 'passthrough';
  sourceFormat = 'md';
  needsOCR = false;

} else if (mimeType === 'text/html' || extension === 'html' || extension === 'htm') {
  strategy = 'cheerio';
  extractionMethod = 'cheerio';
  sourceFormat = 'html';
  needsOCR = false;

} else if (mimeType === 'application/json' || extension === 'json') {
  strategy = 'json_parse';
  extractionMethod = 'json_parse';
  sourceFormat = 'json';
  needsOCR = false;

} else if (
  mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' ||
  extension === 'docx' ||
  magicDOCX
) {
  strategy = 'mammoth';
  extractionMethod = 'mammoth';
  sourceFormat = 'docx';
  needsOCR = false;

} else if (mimeType === 'application/pdf' || extension === 'pdf' || magicPDF) {
  // PDF: tenta pdf-parse primeiro; se texto < 200 chars trata como pdf_scanned
  strategy = 'pdf_parse';
  extractionMethod = 'pdf-parse';
  sourceFormat = 'pdf_text'; // pode ser reclassificado para pdf_scanned após extração
  needsOCR = false; // será reavaliado no nó de extração

} else if (
  mimeType.startsWith('image/') ||
  extension === 'png' ||
  extension === 'jpg' ||
  extension === 'jpeg' ||
  extension === 'webp' ||
  magicPNG ||
  magicJPEG
) {
  strategy = 'vision';
  extractionMethod = 'claude-vision';
  sourceFormat = 'image';
  needsOCR = true;

} else if (mimeType === 'message/rfc822' || extension === 'eml') {
  strategy = 'mailparser';
  extractionMethod = 'mailparser';
  sourceFormat = 'email';
  needsOCR = false;

} else {
  // Formato desconhecido — tenta passthrough como fallback
  strategy = 'passthrough';
  extractionMethod = 'passthrough';
  sourceFormat = 'txt';
  needsOCR = false;
}

return [{
  json: {
    ...item,
    _strategy: strategy,
    _extraction_method: extractionMethod,
    _source_format: sourceFormat,
    _needs_ocr: needsOCR,
    _raw_size_bytes: rawBuffer.length,
    _detection_status: 'ok'
  }
}];

// Extração de texto para formatos não-OCR:
// passthrough (txt/md), cheerio (html), json_parse, mammoth (docx), pdf_parse, mailparser
// Resultado: _normalized_text, _extraction_warnings, _pages, _tables, _images

const item = $input.first().json;
const strategy = item._strategy;
const mimeType = item.document_metadata?.mime_type || '';

let normalizedText = '';
let extractionWarnings = [];
let pageCount = 1;
let tablesDetected = 0;
let imagesExtracted = 0;
let emailHeaders = null;
let attachmentsListed = [];
let needsOCR = item._needs_ocr || false;

const rawBuffer = Buffer.from(item.document_bytes_base64, 'base64');

try {
  if (strategy === 'passthrough') {
    // Detecta encoding: tenta UTF-8, fallback para Latin-1
    try {
      normalizedText = rawBuffer.toString('utf8');
      // Verifica se tem replacement chars (indica encoding errado)
      if (normalizedText.includes('\uFFFD')) {
        normalizedText = rawBuffer.toString('latin1');
        extractionWarnings.push('encoding_converted_latin1_to_utf8');
      }
    } catch (encErr) {
      normalizedText = rawBuffer.toString('latin1');
      extractionWarnings.push('encoding_fallback_latin1');
    }

  } else if (strategy === 'json_parse') {
    const raw = rawBuffer.toString('utf8');
    try {
      const parsed = JSON.parse(raw);
      normalizedText = JSON.stringify(parsed, null, 2);
    } catch (jsonErr) {
      extractionWarnings.push(`json_parse_error: ${jsonErr.message}`);
      normalizedText = raw; // fallback: texto bruto
    }

  } else if (strategy === 'cheerio') {
    // Extração via cheerio não disponível nativamente no n8n Code node
    // Implementação: extrai texto removendo tags HTML manualmente
    const htmlText = rawBuffer.toString('utf8');
    // Remove scripts e styles
    const noScripts = htmlText
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
    // Remove demais tags
    normalizedText = noScripts
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/p>/gi, '\n\n')
      .replace(/<\/div>/gi, '\n')
      .replace(/<\/h[1-6]>/gi, '\n\n')
      .replace(/<[^>]+>/g, '')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&nbsp;/g, ' ')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
    extractionWarnings.push('html_extracted_via_regex_fallback');

  } else if (strategy === 'mammoth') {
    // mammoth não está disponível no n8n Code node por padrão
    // Retorna indicação para processamento externo via HTTP
    extractionWarnings.push('mammoth_not_available_in_node — use HTTP Request para serviço externo de extração DOCX');
    // Emite base64 para tratamento downstream
    normalizedText = `[DOCX_EXTRACTION_PENDING: ${item.document_bytes_base64.slice(0, 20)}...]`;

  } else if (strategy === 'pdf_parse') {
    // pdf-parse não está disponível no n8n Code node por padrão
    // Estratégia: verifica se texto simples embutido no buffer (PDFs simples)
    const pdfText = rawBuffer.toString('binary');
    // Extração heurística de texto em PDFs simples (BT/ET blocks)
    const textMatches = pdfText.match(/BT[\s\S]*?ET/g) || [];
    const extractedFragments = [];
    for (const block of textMatches) {
      const strings = block.match(/\(([^)]+)\)\s*Tj/g) || [];
      for (const s of strings) {
        const text = s.replace(/\(([^)]+)\)\s*Tj/, '$1').trim();
        if (text) extractedFragments.push(text);
      }
    }
    normalizedText = extractedFragments.join(' ');

    // Heurística: se texto extraído < 200 chars → pdf_scanned
    if (normalizedText.length < 200) {
      needsOCR = true;
      normalizedText = '';
      extractionWarnings.push('pdf_text_below_threshold_routing_to_ocr');
    } else {
      extractionWarnings.push('pdf_extracted_via_heuristic — qualidade pode variar; recomendado serviço pdf-parse externo');
    }

  } else if (strategy === 'mailparser') {
    // mailparser não disponível no Code node
    // Extração heurística de email RFC 822
    const emlText = rawBuffer.toString('utf8');
    const lines = emlText.split('\n');
    let inBody = false;
    const headerLines = {};
    const bodyLines = [];

    for (const line of lines) {
      if (!inBody) {
        if (line.trim() === '') {
          inBody = true;
          continue;
        }
        const colonIdx = line.indexOf(':');
        if (colonIdx > 0) {
          const key = line.slice(0, colonIdx).toLowerCase().trim();
          const value = line.slice(colonIdx + 1).trim();
          headerLines[key] = value;
        }
      } else {
        bodyLines.push(line);
      }
    }

    emailHeaders = {
      from: headerLines['from'] || null,
      to: headerLines['to'] ? [headerLines['to']] : [],
      subject: headerLines['subject'] || null,
      date: headerLines['date'] || null
    };

    normalizedText = bodyLines.join('\n').trim();

    if (!normalizedText) {
      extractionWarnings.push('email_empty_body');
    }
    extractionWarnings.push('email_extracted_via_regex_fallback');
  }

} catch (extractErr) {
  return [{
    json: {
      ...item,
      _normalized_text: '',
      _extraction_warnings: [`extraction_error: ${extractErr.message}`],
      _extraction_status: 'failed',
      _needs_ocr: needsOCR,
      _g1_reason: 'g1_normalization_failed',
      _g1_detail: `Erro na extração de texto (${strategy}): ${extractErr.message}`
    }
  }];
}

// Casos especiais §4.5
if (item._raw_size_bytes < 50 && strategy !== 'pdf_parse') {
  extractionWarnings.push('empty_or_truncated');
}

if (
  (strategy === 'vision' || strategy === 'pdf_parse') &&
  normalizedText.length > 0 &&
  normalizedText.length < 10
) {
  extractionWarnings.push('low_text_density');
}

return [{
  json: {
    ...item,
    _normalized_text: normalizedText,
    _extraction_warnings: extractionWarnings,
    _page_count: pageCount,
    _tables_detected: tablesDetected,
    _images_extracted: imagesExtracted,
    _email_headers: emailHeaders,
    _attachments_listed: attachmentsListed,
    _extraction_status: 'ok',
    _needs_ocr: needsOCR
  }
}];

