parameters.jsCode:
// Extrai o texto da resposta do LLM (Anthropic, OpenAI ou DeepSeek)
// e prepara para o nó de montagem do envelope

const ocrResponse = $input.first().json;
const prevItems = $('Precisa OCR?').first().json;

let normalizedText = '';
let ocrConfidence = 0.85; // estimativa padrão
const extractionWarnings = prevItems._extraction_warnings || [];

try {
  // Formato Anthropic: response.content[0].text
  if (ocrResponse.content && Array.isArray(ocrResponse.content)) {
    normalizedText = ocrResponse.content
      .filter(c => c.type === 'text')
      .map(c => c.text)
      .join('\n');
  }
  // Formato OpenAI / DeepSeek: choices[0].message.content
  else if (ocrResponse.choices && Array.isArray(ocrResponse.choices)) {
    normalizedText = ocrResponse.choices[0]?.message?.content || '';
  }

  if (!normalizedText) {
    extractionWarnings.push('ocr_response_empty');
  }

  // Heurística de confiança: presença de [ILLEGIBLE] reduz estimativa
  const illegibleCount = (normalizedText.match(/\[ILLEGIBLE\]/g) || []).length;
  if (illegibleCount > 0) {
    ocrConfidence = Math.max(0.3, ocrConfidence - illegibleCount * 0.1);
    extractionWarnings.push(`ocr_illegible_fragments: ${illegibleCount}`);
  }

  if (normalizedText.length < 10) {
    extractionWarnings.push('low_text_density');
  }

} catch (e) {
  extractionWarnings.push(`ocr_processing_error: ${e.message}`);
}

return [{
  json: {
    ...prevItems,
    _normalized_text: normalizedText,
    _extraction_warnings: extractionWarnings,
    _ocr_confidence: ocrConfidence,
    _source_format: prevItems._source_format === 'pdf_text' ? 'pdf_scanned' : prevItems._source_format,
    _extraction_method: 'claude-vision',
    _extraction_status: normalizedText ? 'ok' : 'failed'
  }
}];

// Monta o envelope de output conforme spec §4.4
// Alimentado pela rota sem OCR (Extrair texto) ou com OCR (Processar resposta OCR)

const item = $input.first().json;

const normalizedText = item._normalized_text || '';
const charCount = normalizedText.length;
const MAX_CHARS = parseInt($env.MAX_NORMALIZED_CHARS || '200000', 10);

// Gate G1 — validações de saída do Normalizador
const g1Warnings = item._extraction_warnings || [];

// G1: texto não-vazio
if (!normalizedText.trim()) {
  const reason = g1Warnings.includes('email_empty_body')
    ? 'email_empty_body'
    : g1Warnings.includes('pdf_password_protected')
    ? 'pdf_password_protected'
    : g1Warnings.includes('empty_or_truncated')
    ? 'empty_or_truncated'
    : 'g1_normalization_failed';

  return [{
    json: {
      _envelope_status: 'failed',
      _g1_reason: 'g1_normalization_failed',
      _g1_detail: `Texto normalizado vazio. Causa: ${reason}`,
      ingestion_id: item.ingestion_id,
      project_id: item.project_id,
      callback_url: item.callback_url
    }
  }];
}

// G1: tamanho ≤ 200k chars
if (charCount > MAX_CHARS) {
  return [{
    json: {
      _envelope_status: 'failed',
      _g1_reason: 'g1_normalization_failed',
      _g1_detail: `Texto normalizado excede ${MAX_CHARS} chars. Obtido: ${charCount} chars`,
      ingestion_id: item.ingestion_id,
      project_id: item.project_id,
      callback_url: item.callback_url
    }
  }];
}

// G1: extraction_metadata completo
if (!item._source_format || !item._extraction_method) {
  return [{
    json: {
      _envelope_status: 'failed',
      _g1_reason: 'g1_normalization_failed',
      _g1_detail: 'extraction_metadata incompleto: source_format ou extraction_method ausente',
      ingestion_id: item.ingestion_id,
      project_id: item.project_id,
      callback_url: item.callback_url
    }
  }];
}

// Monta envelope conforme §4.4
const envelope = {
  ingestion_id: item.ingestion_id,
  project_id: item.project_id,
  normalized_text: normalizedText,
  extraction_metadata: {
    source_format: item._source_format,
    original_size_bytes: item.document_metadata?.size_bytes || item._raw_size_bytes || 0,
    normalized_char_count: charCount,
    extraction_method: item._extraction_method,
    extraction_warnings: g1Warnings,
    ocr_confidence_estimate: item._ocr_confidence || null,
    page_count: item._page_count || 1,
    tables_detected: item._tables_detected || 0,
    images_extracted: item._images_extracted || 0,
    email_headers: item._email_headers || null,
    attachments_listed: item._attachments_listed || []
  },
  provider_chain: item.provider_chain,
  callback_url: item.callback_url,
  received_at: item._received_at || new Date().toISOString()
};

return [{
  json: {
    _envelope_status: 'ok',
    envelope: envelope,
    ingestion_id: item.ingestion_id,
    project_id: item.project_id,
    callback_url: item.callback_url
  }
}];

// Assina o payload com HMAC X-Normalizer-Signature usando NORMALIZER_SECRET
// e prepara para envio ao Conferente

const crypto = require('crypto');
const item = $input.first().json;
const envelope = item.envelope;

const normalizerSecret = $env.NORMALIZER_SECRET || '';

if (!normalizerSecret) {
  return [{
    json: {
      ...item,
      _dispatch_status: 'failed',
      _dispatch_error: 'NORMALIZER_SECRET não configurado no ambiente n8n'
    }
  }];
}

const bodyStr = JSON.stringify(envelope);
const hmacSignature = 'sha256=' + crypto
  .createHmac('sha256', normalizerSecret)
  .update(bodyStr)
  .digest('hex');

return [{
  json: {
    ...item,
    _hmac_signature: hmacSignature,
    _body_to_send: bodyStr,
    _dispatch_status: 'ready'
  }
}];
